async (page) => {
  // Save the MutationObserver quest accepter as a reusable helper
  await page.evaluate(() => {
    window._setupQuestObserver = () => {
      window._questAccepted = false;
      const questPanel = document.getElementById('quest');
      if (!questPanel || window._questObserver) return;
      const observer = new MutationObserver(() => {
        const display = window.getComputedStyle(questPanel).display;
        if (display !== 'none' && !window._questAccepted) {
          setTimeout(() => {
            const btn = document.getElementById('quest-button');
            if (btn && window.getComputedStyle(questPanel).display !== 'none') {
              window._questAccepted = true;
              btn.click();
            }
          }, 150);
        }
      });
      observer.observe(questPanel, { attributes: true, attributeFilter: ['style', 'class'] });
      observer.observe(document.body, { childList: true, subtree: false });
      window._questObserver = observer;
    };
    window._setupQuestObserver();
  });

  // Now check quest objectives and check items needed
  const questInfo = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({
      foresting: s.quests.find(q => q.key === 'foresting'),
      inventory: s.inventory,
      pos: s.player_position
    });
  });
  return questInfo;
}

