async (page) => {
  const questInfo = await page.evaluate(() => {
    const quests = window.game?.quests?.quests;
    if (!quests) return 'no quests object';
    const result = [];
    for (const [key, q] of Object.entries(quests)) {
      if (q.started || ['foresting', 'scavenger', 'anvilsEchoes'].includes(key)) {
        result.push({
          key,
          name: q.name,
          stage: q.stage,
          stageCount: q.stageCount,
          started: q.started,
          description: q.description,
          tasks: q.tasks ? q.tasks.map(t => ({ text: t.text, npc: t.npc, mob: t.mob, item: t.item, stage: t.stage })) : []
        });
      }
    }
    return JSON.stringify(result, null, 2);
  });
  return questInfo;
}

