    const g = window.game;
    const vgX = 136, vgY = 146;
    const camera = g.renderer?.camera;
    if (camera) {
      const tileSize = g.renderer.actualTileSize || 48;
      const screenX = (vgX * tileSize) - camera.x;
      const screenY = (vgY * tileSize) - camera.y;
      const canvas = document.getElementById('canvas');
      console.log('VG screen pos:', screenX, screenY);
      canvas.dispatchEvent(new MouseEvent('click', { clientX: screenX, clientY: screenY, bubbles: true }));
    }
