async (page) => {
  await page.evaluate(() => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('click', { clientX: 256, clientY: 408, bubbles: true }));
  });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const vg = s.nearby_entities.find(e => e.name === 'Village Girl');
    const g = window.game;
    const camera = g.renderer?.camera;
    const tileToCanvas = (tileX, tileY) => ({
      cx: Math.round((tileX * 16 - camera.x) * 3),
      cy: Math.round((tileY * 16 - camera.y) * 3)
    });
    const vgCoords = vg ? tileToCanvas(vg.x, vg.y) : null;
    return JSON.stringify({ pos: s.player_position, gridPos: { x: g.player.gridX, y: g.player.gridY }, vg: vg ? { dist: vg.distance, on_screen: vg.on_screen, coords: vgCoords } : null });
  });
  return state;
}

